"use strict";(globalThis.webpackChunkwebsite=globalThis.webpackChunkwebsite||[]).push([[115],{7719(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"category","label":"Overview","items":[{"type":"link","href":"/sora-docs/en/docs/","label":"SORA \u2014 Signals Offensive Radio Auditor","docId":"index","unlisted":false},{"type":"link","href":"/sora-docs/en/docs/architecture/packet_lifecycle","label":"Lifecycle of a Packet: From Antenna to TUI","docId":"architecture/packet_lifecycle","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Legal & Compliance","items":[{"type":"link","href":"/sora-docs/en/docs/DISCLAIMER","label":"Legal Disclaimer","docId":"DISCLAIMER","unlisted":false},{"type":"link","href":"/sora-docs/en/docs/COMPLIANCE","label":"Compliance & Regulatory Standards","docId":"COMPLIANCE","unlisted":false},{"type":"link","href":"/sora-docs/en/docs/LICENSE","label":"License","docId":"LICENSE","unlisted":false},{"type":"link","href":"/sora-docs/en/docs/plugins/LICENSE","label":"MIT License (Plugins Only)","docId":"plugins/LICENSE","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Rust Core Layer","items":[{"type":"link","href":"/sora-docs/en/docs/rust/overview","label":"High-Level Core Architecture (Rust Core)","docId":"rust/overview","unlisted":false},{"type":"link","href":"/sora-docs/en/docs/rust/packet_engine","label":"PacketEngine & AF_PACKET Deep Dive","docId":"rust/packet_engine","unlisted":false},{"type":"link","href":"/sora-docs/en/docs/rust/tx_queue","label":"Dispatching & StealthEngine (TxQueue)","docId":"rust/tx_queue","unlisted":false},{"type":"link","href":"/sora-docs/en/docs/rust/nl80211","label":"nl80211 & Hybrid Interface Control","docId":"rust/nl80211","unlisted":false},{"type":"link","href":"/sora-docs/en/docs/rust/adapter_layer","label":"Adapter Layer and Recovery","docId":"rust/adapter_layer","unlisted":false},{"type":"link","href":"/sora-docs/en/docs/rust/security","label":"Security Model and Memory Safety","docId":"rust/security","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Python Orchestrator","items":[{"type":"link","href":"/sora-docs/en/docs/python/overview","label":"Python Orchestrator: High-Level Overview","docId":"python/overview","unlisted":false},{"type":"link","href":"/sora-docs/en/docs/python/fsm","label":"AttackController & The GIL Escape","docId":"python/fsm","unlisted":false},{"type":"link","href":"/sora-docs/en/docs/python/config_manager","label":"ConfigManager: Advanced Template Rendering & Risk Matrix","docId":"python/config_manager","unlisted":false},{"type":"link","href":"/sora-docs/en/docs/python/persistence","label":"Persistence: SQLite & Pcapng Offsets","docId":"python/persistence","unlisted":false},{"type":"link","href":"/sora-docs/en/docs/python/tui_internals","label":"TUI Internals: Textual & Event Loop Optimization","docId":"python/tui_internals","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"IPC & Bridging","items":[{"type":"link","href":"/sora-docs/en/docs/ipc/architecture","label":"IPC Architecture: The PyO3 Bridge & Marshalling","docId":"ipc/architecture","unlisted":false},{"type":"link","href":"/sora-docs/en/docs/ipc/error_bridge","label":"Error Bridge: Panic & Exception Mapping","docId":"ipc/error_bridge","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"NDJSON Plugins","items":[{"type":"link","href":"/sora-docs/en/docs/plugins/overview","label":"Plugin Architecture and Lifecycle","docId":"plugins/overview","unlisted":false},{"type":"link","href":"/sora-docs/en/docs/plugins/ndjson_api","label":"NDJSON API Specification (Plugin Subprocess IPC)","docId":"plugins/ndjson_api","unlisted":false},{"type":"link","href":"/sora-docs/en/docs/plugins/creating_plugin","label":"Practical Guide to Creating a Plugin","docId":"plugins/creating_plugin","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Advanced Diagnostics","items":[{"type":"link","href":"/sora-docs/en/docs/debugging","label":"Debugging and Troubleshooting (Kernel Level)","docId":"debugging","unlisted":false},{"type":"link","href":"/sora-docs/en/docs/profiling","label":"End-to-End Profiling Methodology","docId":"profiling","unlisted":false}],"collapsed":true,"collapsible":true}]},"docs":{"architecture/packet_lifecycle":{"id":"architecture/packet_lifecycle","title":"Lifecycle of a Packet: From Antenna to TUI","description":"Understanding the lifecycle of a packet in SORA is critical for performance evaluation and data integrity assurance. This section describes the journey of a single 802.11 frame through all layers of the system.","sidebar":"tutorialSidebar"},"COMPLIANCE":{"id":"COMPLIANCE","title":"Compliance & Regulatory Standards","description":"English | \u0420\u0443\u0441\u0441\u043a\u0438\u0439 | \u4e2d\u6587","sidebar":"tutorialSidebar"},"debugging":{"id":"debugging","title":"Debugging and Troubleshooting (Kernel Level)","description":"The documentation for a professional audit tool would be incomplete without a section on deep diagnostics. Going beyond the Python interface and understanding system calls is a key skill for a SORA developer.","sidebar":"tutorialSidebar"},"DISCLAIMER":{"id":"DISCLAIMER","title":"Legal Disclaimer","description":"English | \u0420\u0443\u0441\u0441\u043a\u0438\u0439 | \u4e2d\u6587","sidebar":"tutorialSidebar"},"index":{"id":"index","title":"SORA \u2014 Signals Offensive Radio Auditor","description":"English | \u0420\u0443\u0441\u0441\u043a\u0438\u0439 | \u4e2d\u6587","sidebar":"tutorialSidebar"},"ipc/architecture":{"id":"ipc/architecture","title":"IPC Architecture: The PyO3 Bridge & Marshalling","description":"The Inter-Process Communication (IPC) system in SORA is a high-performance bridge between the native multithreaded Rust core and the asynchronous Python interpreter. It is based on the PyO3 library and the crossbeam-channel shared queue mechanism.","sidebar":"tutorialSidebar"},"ipc/error_bridge":{"id":"ipc/error_bridge","title":"Error Bridge: Panic & Exception Mapping","description":"In SORA\'s multi-language architecture (Rust + Python), correct error handling at the FFI boundary is critical for the stability of the entire system. This section describes how panics in native code and system call errors are translated into Python exceptions.","sidebar":"tutorialSidebar"},"LICENSE":{"id":"LICENSE","title":"License","description":"SORA Core and Python layer are distributed under the terms of the GNU General Public License v3.0.","sidebar":"tutorialSidebar"},"plugins/creating_plugin":{"id":"plugins/creating_plugin","title":"Practical Guide to Creating a Plugin","description":"Creating an extension for SORA does not require deep knowledge of the Rust core\'s inner workings. A plugin interacts with the system as an isolated process, exchanging messages in text format.","sidebar":"tutorialSidebar"},"plugins/LICENSE":{"id":"plugins/LICENSE","title":"MIT License (Plugins Only)","description":"This license applies exclusively to the SORA plugin ecosystem to encourage community development and integration.","sidebar":"tutorialSidebar"},"plugins/ndjson_api":{"id":"plugins/ndjson_api","title":"NDJSON API Specification (Plugin Subprocess IPC)","description":"In SORA, the plugin architecture is implemented via Subprocess IPC, where data exchange occurs over the NDJSON protocol. This ensures total isolation and the ability to use any programming language without being tied to Rust\'s ABI or Python\'s GIL.","sidebar":"tutorialSidebar"},"plugins/overview":{"id":"plugins/overview","title":"Plugin Architecture and Lifecycle","description":"SORA\'s plugin system is designed with a focus on maximum isolation, core stability, and language independence. Unlike monolithic architectures where plugins run in the same address space as the main application, SORA uses a process-based isolation model.","sidebar":"tutorialSidebar"},"profiling":{"id":"profiling","title":"End-to-End Profiling Methodology","description":"To ensure 10Gbps-level performance and handle high-load Wi-Fi networks, deep analysis of delays at every processing stage is required.","sidebar":"tutorialSidebar"},"python/config_manager":{"id":"python/config_manager","title":"ConfigManager: Advanced Template Rendering & Risk Matrix","description":"ConfigManager in SORA is a critical link that transforms abstract audit goals into concrete system daemon configurations. This section describes the internal rendering logic and the risk analysis of hostapd parameters.","sidebar":"tutorialSidebar"},"python/fsm":{"id":"python/fsm","title":"AttackController & The GIL Escape","description":"This section documents SORA\'s high-level control logic and the architectural solution used to bypass the limitations of the Python Global Interpreter Lock (GIL).","sidebar":"tutorialSidebar"},"python/overview":{"id":"python/overview","title":"Python Orchestrator: High-Level Overview","description":"The SORA management layer is fully implemented in Python. Unlike the Rust core, which scrupulously saves microseconds, the Python layer operates at the macrotask level: interface rendering, session logging, finite state machine (FSM) management, and configuration rendering.","sidebar":"tutorialSidebar"},"python/persistence":{"id":"python/persistence","title":"Persistence: SQLite & Pcapng Offsets","description":"This section describes the long-term data storage mechanisms in SORA. The system combines a relational database (SQLite) for metadata and a structured binary log (Pcapng) for radio frequency frames.","sidebar":"tutorialSidebar"},"python/tui_internals":{"id":"python/tui_internals","title":"TUI Internals: Textual & Event Loop Optimization","description":"The SORA interface is built on the Textual framework (Async TUI). The main task of this layer is to visualize the high-speed event stream from the Rust core without blocking the main rendering loop.","sidebar":"tutorialSidebar"},"rust/adapter_layer":{"id":"rust/adapter_layer","title":"Adapter Layer and Recovery","description":"The adapter layer is responsible for the logical state management of the physical Wi-Fi interface. During active audits (AAL, EvilTwin, Deauth), interfaces are subjected to extreme loads, which can lead to failures at the Kernel Driver level (e.g., driver panics in ath9k or rtw88).","sidebar":"tutorialSidebar"},"rust/nl80211":{"id":"rust/nl80211","title":"nl80211 & Hybrid Interface Control","description":"This section describes the architecture of Wi-Fi adapter management in SORA. Mode switching (Managed/Monitor) and frequency changes are implemented through a hybrid mechanism that combines the modern Generic Netlink (nl80211) protocol and classic IOCTL system calls.","sidebar":"tutorialSidebar"},"rust/overview":{"id":"rust/overview","title":"High-Level Core Architecture (Rust Core)","description":"The core of the SORA project (sora-core) is a compiled library in Rust, integrated into the Python environment through the PyO3 interface. The primary purpose of the core is to execute high-load network operations that require microsecond precision and the absence of Garbage Collector (GC) pauses inherent in Python.","sidebar":"tutorialSidebar"},"rust/packet_engine":{"id":"rust/packet_engine","title":"PacketEngine & AF_PACKET Deep Dive","description":"This section describes the low-level implementation of packet capture and injection in SORA. The architecture is oriented toward low-latency and direct interaction with the Linux kernel networking stack through the AF_PACKET socket family.","sidebar":"tutorialSidebar"},"rust/security":{"id":"rust/security","title":"Security Model and Memory Safety","description":"The SORA project operates at a low level of the Linux networking stack, which requires special attention to privilege management and memory safety. This section documents the Threat Model and the audit of unsafe code.","sidebar":"tutorialSidebar"},"rust/tx_queue":{"id":"rust/tx_queue","title":"Dispatching & StealthEngine (TxQueue)","description":"The tx_dispatch module is responsible for sending generated 802.11 frames to the network. The delivery architecture is designed to prevent Head-of-Line Blocking and minimize the probability of detection by WIDS/WIPS (Wireless Intrusion Detection Systems).","sidebar":"tutorialSidebar"}}}}')}}]);